#include <stdio.h>
#include <stdlib.h>

int min(int a, int b) { return a < b ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **A = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            A[i] = (int *)malloc(M * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%1d", &A[i][j]);
            }
        }
        int **dp = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            dp[i] = (int *)malloc(M * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                dp[i][j] = -1;
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (A[i][j] == 1) {
                    dp[i][j] = 0;
                } else {
                    int minMoves = -1;
                    for (int k = 0; k < N; k++) {
                        if (A[k][j] == 1) {
                            if (minMoves == -1) {
                                minMoves = 1;
                            } else {
                                minMoves = min(minMoves, 1);
                            }
                        }
                    }
                    for (int k = 0; k < M; k++) {
                        if (A[i][k] == 1) {
                            if (minMoves == -1) {
                                minMoves = 1;
                            } else {
                                minMoves = min(minMoves, 1);
                            }
                        }
                    }
                    dp[i][j] = minMoves;
                }
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                printf("%d ", dp[i][j]);
            }
            printf("\n");
        }
        for (int i = 0; i < N; i++) {
            free(A[i]);
            free(dp[i]);
        }
        free(A);
        free(dp);
    }
    return 0;
}

